#!/usr/bin/env python3
"""Self-extracting launcher for the Q-Learning Pricing App.
Run: python3 run_app.py
"""
import base64, io, zipfile, subprocess, sys, os, tempfile, shutil

DATA = """"""


def main():
    raw = base64.b64decode(DATA)
    tmp = tempfile.mkdtemp(prefix="ql_app_")
    print(f"Extracting to {tmp} ...")
    with zipfile.ZipFile(io.BytesIO(raw)) as zf:
        zf.extractall(tmp)
    pkgs = ["streamlit", "numpy", "pandas", "numba"]
    for pkg in pkgs:
        try:
            __import__(pkg)
        except ImportError:
            print(f"Installing {pkg}...")
            subprocess.check_call([sys.executable, "-m", "pip", "install", pkg, "-q"])
    entry = os.path.join(tmp, "streamlit_app", "Welcome.py")
    print("Launching app...")
    try:
        subprocess.run([sys.executable, "-m", "streamlit", "run", entry,
                       "--server.port", "8503"], cwd=tmp)
    finally:
        shutil.rmtree(tmp, ignore_errors=True)

if __name__ == "__main__":
    main()
